import{_ as a,o as i,c as t,ag as s}from"./chunks/framework.DXGyWiRo.js";const u=JSON.parse('{"title":"SEED Studio Overclocking Guide","description":"","frontmatter":{},"headers":[],"relativePath":"microcontrollers-and-socs/raspberry-pi/overclocking-raspberry-pi-4/seed-studio-overclocking-guide.md","filePath":"microcontrollers-and-socs/raspberry-pi/overclocking-raspberry-pi-4/seed-studio-overclocking-guide.md"}'),o={name:"microcontrollers-and-socs/raspberry-pi/overclocking-raspberry-pi-4/seed-studio-overclocking-guide.md"};function r(n,e,l,p,h,c){return i(),t("div",null,[...e[0]||(e[0]=[s(`<h1 id="seed-studio-overclocking-guide" tabindex="-1">SEED Studio Overclocking Guide <a class="header-anchor" href="#seed-studio-overclocking-guide" aria-label="Permalink to &quot;SEED Studio Overclocking Guide&quot;">​</a></h1><h2 id="how-to-safely-overclock-your-raspberry-pi-4-to-2-147ghz" tabindex="-1">How to Safely Overclock your Raspberry Pi 4 to 2.147GHz <a class="header-anchor" href="#how-to-safely-overclock-your-raspberry-pi-4-to-2-147ghz" aria-label="Permalink to &quot;How to Safely Overclock your Raspberry Pi 4 to 2.147GHz&quot;">​</a></h2><p>By <a href="https://www.seeedstudio.com/blog/author/shawn/" target="_blank" rel="noreferrer">Shawn </a>4 years ago</p><p>The Raspberry Pi 4 is arguably the best Single Board Computer, but did you know you can overclock it to squeeze out even more performance? Yes, its base ARM Cortex-A72 processor with max clock speeds of 1.5GHz can actually be overclocked to up to 2.147GHz !</p><p>In today’s tutorial, we’ll teach you how you can safely overclock your Pi 4! Do still try this at your own risk!</p><figure><img src="https://www.seeedstudio.com/blog/wp-content/uploads/2021/06/Overclock-1030x442.png" alt="" height="442" width="1030"><figcaption></figcaption></figure><hr><h3 id="steps-to-overclock-your-raspberry-pi-4" tabindex="-1"><strong>Steps to Overclock your Raspberry Pi 4</strong> <a class="header-anchor" href="#steps-to-overclock-your-raspberry-pi-4" aria-label="Permalink to &quot;**Steps to Overclock your Raspberry Pi 4**&quot;">​</a></h3><h4 id="warranty-and-risks" tabindex="-1"><strong>Warranty and Risks</strong> <a class="header-anchor" href="#warranty-and-risks" aria-label="Permalink to &quot;**Warranty and Risks**&quot;">​</a></h4><p>In most cases, overclocking is safe and will not void your warranty <strong>if done so in an appropriate manner</strong>. However, you should still be aware that there are several settings that will void the warranty by flipping a hardware switch inside your Pi:</p><ul><li>over_voltage greater than 6</li><li>force_turbo=1</li><li>temp_limit greater than 85</li></ul><p>There will always be a risk of your Raspberry Pi 4 overheating while being overclocked. This tutorial will teach you the safest method, but please be aware of and accept the risks that you will undertake by continuing!</p><hr><h4 id="step-1-prepare-the-hardware" tabindex="-1"><strong>Step 1: Prepare the Hardware</strong> <a class="header-anchor" href="#step-1-prepare-the-hardware" aria-label="Permalink to &quot;**Step 1: Prepare the Hardware**&quot;">​</a></h4><p>Before we get started, let’s first go through what you’ll need for this tutorial. Apart from your <a href="https://www.seeedstudio.com/Raspberry-Pi-4-Computer-Model-B-4GB-p-4077.html?utm_source=blog&amp;utm_medium=blog" target="_blank" rel="noreferrer">R</a><a href="https://www.seeedstudio.com/Raspberry-Pi-4-Computer-Model-B-4GB-p-4077.html" target="_blank" rel="noreferrer">asp</a><a href="https://www.seeedstudio.com/Raspberry-Pi-4-Computer-Model-B-4GB-p-4077.html?utm_source=blog&amp;utm_medium=blog" target="_blank" rel="noreferrer">berry Pi 4</a>, you’ll need:</p><ul><li>A Raspberry Pi 4 Cooling Solution – Heatsink + Fan recommended</li><li>SD Card with Raspberry Pi OS Installed</li><li>A <a href="https://www.seeedstudio.com/power-c-865.html?utm_source=blog&amp;utm_medium=blog" target="_blank" rel="noreferrer">Reliable Power Supply</a> (official version is highly recommended) to ensure your Pi is not being starved of power</li></ul><h4 id="recommended-cooling-solution-black-warrior-ice-tower-cpu-cooling-fan" tabindex="-1"><strong>Recommended Cooling Solution:</strong> <a href="https://www.seeedstudio.com/Black-Warrior-ICE-Tower-CPU-Cooling-Fan-for-Raspberry-Pi-Support-Pi-4-p-4319.html?utm_source=blog&amp;utm_medium=blog" target="_blank" rel="noreferrer"><strong>Black Warrior ICE Tower CPU Cooling Fan</strong></a> <a class="header-anchor" href="#recommended-cooling-solution-black-warrior-ice-tower-cpu-cooling-fan" aria-label="Permalink to &quot;**Recommended Cooling Solution:** [**Black Warrior ICE Tower CPU Cooling Fan**](https://www.seeedstudio.com/Black-Warrior-ICE-Tower-CPU-Cooling-Fan-for-Raspberry-Pi-Support-Pi-4-p-4319.html?utm\\_source=blog\\&amp;utm\\_medium=blog)&quot;">​</a></h4><p>Undoubtedly the biggest issue with the Raspberry Pi 4 is thermal issues and throttling. With the Pi 4 capable of reaching insane temperatures (even beyond 85°C) without overclocking, you’ll definitely need a cooling solution in place if you want to overclock it!</p><figure><img src="https://www.seeedstudio.com/blog/wp-content/uploads/2022/03/dianl_1-1.jpg" alt="" height="525" width="700"><figcaption><p><em>Black Warrior ICE Tower CPU Cooling Fan for Raspberry Pi</em></p></figcaption></figure><p>One of the hot favourites here at Seeed is the Black Warrior ICE Tower CPU Cooling Fan for Raspberry Pi. It’s capable of reducing temperatures from 80℃ to 40℃ and is designed by 52PI, a world-leading Raspberry Pi accessories manufacturer. To achieve such a level of cooling, this cooling kit includes a 5mm copper tube, multi-layered heat sinks, and a fan with 7 blades.</p><p>If you’re looking for a cooling solution that’s more discrete, you can check out our list of Raspberry Pi <a href="https://www.seeedstudio.com/cases-c-850.html?utm_source=blog&amp;utm_medium=blog" target="_blank" rel="noreferrer">cooling cases</a> and <a href="https://www.seeedstudio.com/heat-sink-c-849.html?utm_source=blog&amp;utm_medium=blog" target="_blank" rel="noreferrer">heat sinks!</a></p><h4 id="step-2-update-your-raspberry-pi-4-firmware" tabindex="-1"><strong>Step 2: Update your Raspberry Pi 4 Firmware</strong> <a class="header-anchor" href="#step-2-update-your-raspberry-pi-4-firmware" aria-label="Permalink to &quot;**Step 2: Update your Raspberry Pi 4 Firmware**&quot;">​</a></h4><p>For the latest overclocking capabilities on the Pi 4, always update it to the latest version. This will give you the latest performance and reliability optimisations offered, which will improve your ability to reach higher clock speeds!</p><p>Here’s how you can update your Pi 4 to the latest firmware:</p><ol><li>Open the terminal on your Raspberry Pi and enter the following code:</li></ol><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> apt</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> update</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> apt</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> full-upgrade</span></span></code></pre></div><figure><img src="https://www.seeedstudio.com/blog/wp-content/uploads/2022/03/1.1-2.jpg" alt="" height="576" width="1024"><figcaption><p><em>Source:</em> <a href="https://i2.wp.com/tutorial.cytron.io/wp-content/uploads/2021/02/2021-02-15-103416_1920x1080_scrot-1024x576-1.jpg?w=1024&amp;ssl=1"><em>Cytron</em></a></p></figcaption></figure><p>2. Afterwards, reboot the system for the update to be applied!</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> reboot</span></span></code></pre></div><h4 id="step-3-check-the-default-speed-of-cpu" tabindex="-1"><strong>Step 3: Check the Default Speed of CPU</strong> <a class="header-anchor" href="#step-3-check-the-default-speed-of-cpu" aria-label="Permalink to &quot;**Step 3: Check the Default Speed of CPU**&quot;">​</a></h4><p>The next step before you overclock your Pi 4 is to check your CPU base speed. It is good to check the default clock speed to see the changeable value, which can be done by opening the command line and entering the following:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">Lscpu</span></span></code></pre></div><p>or</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cat</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /sys/devices/system/cpu/cpu0/cpufreq/scaling_cur_freq</span></span></code></pre></div><figure><img src="https://www.seeedstudio.com/blog/wp-content/uploads/2022/03/2.1-1.jpg" alt="" height="576" width="1024"><figcaption><p><em>Source:</em> <a href="https://i0.wp.com/tutorial.cytron.io/wp-content/uploads/2021/02/2021-02-15-103734_1920x1080_scrot-1024x184-1.jpg?w=1024&amp;ssl=1"><em>Cytron</em></a></p></figcaption></figure><p>This indicates that my Pi 4 CPU base speed is 600MHz, the speed requested by the kernel!</p><h4 id="step-4-let-s-start-overclocking" tabindex="-1"><strong>Step 4: Let’s start overclocking!</strong> <a class="header-anchor" href="#step-4-let-s-start-overclocking" aria-label="Permalink to &quot;**Step 4: Let’s start overclocking!**&quot;">​</a></h4><p>To overclock your Pi 4, we’ll mainly be <strong>tinkering with the config.txt file</strong> under core configuration settings. Follow the instructions below carefully to avoid any errors.</p><ul><li>Open your terminal window and enter the following code:</li></ul><div class="language-php vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">php</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">sudo</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> nano</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> /</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">boot</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">/</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">config</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">.</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">txt</span></span></code></pre></div><ul><li>Scroll down to the section marked:</li></ul><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>## uncomment to overclock the arm. 700 MHz is the default.</span></span>
<span class="line"><span>## arm_freq=800</span></span></code></pre></div><ul><li>Change the config settings to:</li></ul><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>## uncomment to overclock the arm. 700 MHz is the default.</span></span>
<span class="line"><span>over_voltage=2</span></span>
<span class="line"><span>arm_freq=1750</span></span></code></pre></div><ul><li>Save the file with CTRL+O (press RETURN) and use CTRL+X to exit. Now, restart your Raspberry Pi:</li></ul><div class="language-php vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">php</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">sudo</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> reboot</span></span></code></pre></div><ul><li>Once your Raspberry Pi boots up again, use the vcgencmd command to check your new, faster clock speed:</li></ul><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">watch</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -n</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 1</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> vcgencmd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> measure_clock</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> arm</span></span></code></pre></div><p>This command will monitor your real-time speed. Browse a few web pages on a few tabs and watch your CPU head on up to 1.75GHz!</p><h3 id="step-5-overclocking-your-pi-4-to-even-higher-clock-speed-2ghz" tabindex="-1"><strong>Step 5: Overclocking your Pi 4 to even higher clock speed (2GHz)!</strong> <a class="header-anchor" href="#step-5-overclocking-your-pi-4-to-even-higher-clock-speed-2ghz" aria-label="Permalink to &quot;**Step 5: Overclocking your Pi 4 to even higher clock speed (2GHz)!**&quot;">​</a></h3><p>If you think overclocking it to around 1.75GHz is impressive, let’s take things up a notch, by cranking your Pi 4 CPU to 2.0GHz.</p><p>We will need to increase over_voltage to adjust the core CPU/GPU voltage to accommodate the higher clock speed. We will be cranking the over_voltage value up to 6, which is the <strong>highest without voiding the warranty</strong>.</p><ul><li>Edit the config.txt file with the following settings:</li></ul><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">over_voltage</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">6</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">arm_freq</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">2000</span></span></code></pre></div><ul><li>Save the file and exit Nano by CTRL+O and CTRL+X. Reboot your Raspberry Pi 4 and run:</li></ul><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> reboot</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">watch</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -n</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 1</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> vcgencmd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> measure_clock</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> arm</span></span></code></pre></div><p>Similar to before, you’ll now see the clock speed limit to appear as 2.0GHz!</p><h4 id="step-6-overclocking-your-pi-4-to-the-max-level" tabindex="-1"><strong>Step 6: Overclocking your Pi 4 to the Max level!</strong> <a class="header-anchor" href="#step-6-overclocking-your-pi-4-to-the-max-level" aria-label="Permalink to &quot;**Step 6: Overclocking your Pi 4 to the Max level!**&quot;">​</a></h4><p>Now for the moment you’ve been waiting for, overclocking your Pi 4 to 2.147GHz max clock speed! This time, we’ll also have to boost the gpu_freq by editing the config.txt file once again. </p><p>We’ll set the arm_freq to 2147 and gpu_freq to 750 by changing the following settings:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>over_voltage=6</span></span>
<span class="line"><span>arm_freq=2147</span></span>
<span class="line"><span>gpu_freq=750</span></span></code></pre></div><p>The gpu_freq command will set core_freq, h264_freq, isp_freq, v3d_freq and hevc_freq all together which drives the L2 cache and memory bus for higher performance. A value of 750 is the highest value we’ve gotten after rigorous testing.</p><ul><li>Save the file and exit Nano by CTRL+O and CTRL+X. Reboot your Pi 4 Now and you should see your device running at 2.147GHz!</li></ul><div class="language-python vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">python</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">sudo reboot</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">watch </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">n </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> vcgencmd measure_clock arm</span></span></code></pre></div><p><strong>NOTE:</strong> Some Raspberry Pi 4 boards have failed to boot at this speed or slowed down due to overheating/under-voltage. It’s unlikely for you to run your Pi 4 board at this max speed in the long run, hence we recommend you to settle for arm_freq=2000 / stop at step 5. Do also be reminded to monitor your CPU temperatures, as overheating can cause irreparable damage!</p><hr><h3 id="summary" tabindex="-1"><strong>Summary</strong> <a class="header-anchor" href="#summary" aria-label="Permalink to &quot;**Summary**&quot;">​</a></h3><p>That’s all for today’s tutorial on how you can easily overclock your Raspberry Pi 4. Overclocking your Pi 4 is a rather straightforward way to get extra performance from your CPU, but you should understand the risks and limits of overclocking – it’s definitely safe when done in a controlled manner. Always check the settings that you are about to change before affecting them to avoid voiding your warranty.</p><p>Thanks for reading! PS. Here is a <a href="https://www.raspberrypi.org/documentation/configuration/warning-icons.mdhttps://www.raspberrypi.org/documentation/configuration/warning-icons.md" target="_blank" rel="noreferrer">list of warning icons</a> that may appear on the screen while you are attempting to overclock your Raspberry Pi. Always check if warnings appear or if you have any doubts!</p><p>Keen to learn more? Here are some of our other articles that may interest you:</p><ul><li><a href="https://blog.seeedstudio.com/2021/03/22/machine-learning-powered-inventory-tracking-with-raspberry-pi/" target="_blank" rel="noreferrer">Machine Learning Powered Inventory Tracking with Raspberry Pi</a></li><li><a href="https://blog.seeedstudio.com/2021/02/05/build-a-raspberry-pi-security-camera-using-raspberry-pi-camera/" target="_blank" rel="noreferrer">Build a Raspberry Pi Security Camera using Raspberry Pi Camera!</a></li><li><a href="https://blog.seeedstudio.com/2021/02/04/raspberry-pi-line-following-robot/" target="_blank" rel="noreferrer">Build a Raspberry Pi Line Following Robot!</a></li><li><a href="https://www.seeedstudio.com/blog/2021/01/25/three-methods-to-configure-raspberry-pi-wifi/" target="_blank" rel="noreferrer">How To Configure WiFi on Raspberry Pi: Step By Step Tutorial</a></li></ul>`,71)])])}const g=a(o,[["render",r]]);export{u as __pageData,g as default};
